165: bool RINE_mt6816_spi_data_Get_AngleData(void)
166: {
167:     uint16_t data_t[2];
168:     uint16_t data_r[2];
169:     uint8_t h_count;
170: 
171:     data_t[0] = (uint16_t)((0x80 | 0x03) << 8);
172:     data_t[1] = (uint16_t)((0x80 | 0x04) << 8);
173: 
174:     for(uint8_t i = 0; i < 3; i++)
175:     {
176:         // 读取SPI数据
177:         MT6816_SPI_CS_L();
178:         HAL_SPI_TransmitReceive(&MT6816_SPI_Get_HSPI, (uint8_t*)&data_t[0], (uint8_t*)&data_r[0], 1, HAL_MAX_DELAY);
179:         MT6816_SPI_CS_H();
180: 
181:         MT6816_SPI_CS_L();
182:         HAL_SPI_TransmitReceive(&MT6816_SPI_Get_HSPI, (uint8_t*)&data_t[1], (uint8_t*)&data_r[1], 1, HAL_MAX_DELAY);
183:         MT6816_SPI_CS_H();
184: 
185:         mt6816_spi_data.sample_data = (uint16_t)(((data_r[0] & 0x00FF) << 8) | (data_r[1] & 0x00FF));
186: 
187:         // 奇偶校验
188:         h_count = 0;
189:         for(uint8_t j = 0; j < 16; j++)
190:         {
191:             if(mt6816_spi_data.sample_data & (0x0001 << j))
192:                 h_count++;
193:         }
194: 
195:         if(h_count & 0x01)
196:         {
197:             mt6816_spi_data.parity_ok = false;
198:         }
199:         else
200:         {
201:             mt6816_spi_data.parity_ok = true;
202:             break;
203:         }
204:     }
205: 
206:     if(mt6816_spi_data.parity_ok)
207:     {
208:         mt6816_spi_data.angle = mt6816_spi_data.sample_data >> 2;
209:         mt6816_spi_data.no_magnet_flag = (bool)(mt6816_spi_data.sample_data & (0x0001 << 1));
210: 
211:         if(mt6816_spi_data.no_magnet_flag)   // 磁通不足
212:             return false;
213:         else
214:             return true;
215:     }
216:     else
217:     {
218:         return false;   // 奇偶校验不通过
219:     }
220: }
