50: void calibrate_current_offset(uint16_t sample_times)
51: {
52:     float sum_a = 0.0f;
53:     float sum_b = 0.0f;
54: 
55:     if(sample_times == 0)
56:         sample_times = 1;
57: 
58:     for(uint16_t i = 0; i < sample_times; i++)
59:     {
60:         HAL_ADCEx_InjectedStart(&hadc1);
61:         HAL_ADCEx_InjectedPollForConversion(&hadc1, 10);
62:         HAL_ADCEx_InjectedPollForConversion(&hadc1, 10);
63:         sum_a += ((float)HAL_ADCEx_InjectedGetValue(&hadc1, ADC_INJECTED_RANK_2) - CURRENT_VREF_ADC) * ADCtoI;
64:         sum_b += ((float)HAL_ADCEx_InjectedGetValue(&hadc1, ADC_INJECTED_RANK_1) - CURRENT_VREF_ADC) * ADCtoI;
65:         HAL_ADCEx_InjectedStop(&hadc1);
66:         HAL_Delay(1);
67:     }
68: 
69:     offet_I[0] = sum_a / sample_times;
70:     offet_I[1] = sum_b / sample_times;
71: }
