73: float get_temp(void)
74: {
75:     uint16_t adcvalue = get_adc_xchannel(9);
76: 
77:     if(adcvalue == 0) adcvalue = 1;
78:     if(adcvalue >= 4095) adcvalue = 4094;
79: 
80:     float vadc = adcvalue * ADC_REF_VOLTAGE / ADC_FULL_SCALE;
81:     float Rntc = 10000.0f * vadc / (ADC_REF_VOLTAGE - vadc);
82: 
83:     const float T0 = 298.15f;
84:     const float R0 = 10000.0f;
85:     const float B  = 3950.0f;
86: 
87:     return 1.0f / (1.0f / T0 + logf(Rntc / R0) / B) - 273.15f;
88: }
