void Encoder_Init(encoder_t *enc)
{
    enc->cnt_now = 0;
    enc->cnt_last = 0;
    enc->delta = 0;
    enc->pos_cnt_total = 0;
    enc->pos_rev = 0.0f;
    enc->vel_rps = 0.0f;
    enc->vel_rpm = 0.0f;
    enc->vel_rpm_f = 0.0f;
}

void Encoder_Start(encoder_t *enc, TIM_HandleTypeDef *htim_enc)
{
    // 启动 TIM2 Encoder
    HAL_TIM_Encoder_Start(htim_enc, TIM_CHANNEL_ALL);

    // 清零硬件计数器
    __HAL_TIM_SET_COUNTER(htim_enc, 0);

    // 同步软件状态
    enc->cnt_last = 0;
    enc->pos_cnt_total = 0;
}

void Encoder_Zero(encoder_t *enc, TIM_HandleTypeDef *htim_enc)
{
    __HAL_TIM_SET_COUNTER(htim_enc, 0);
    enc->cnt_last = 0;
    enc->cnt_now = 0;
    enc->delta = 0;
    enc->pos_cnt_total = 0;
    enc->pos_rev = 0.0f;
    enc->vel_rps = 0.0f;
    enc->vel_rpm = 0.0f;
}


