+static inline uint16_t tim_period(TIM_HandleTypeDef *htim)
+{
+    return (uint16_t)(__HAL_TIM_GET_AUTORELOAD(htim) + 1U);
+}
+
+static inline uint16_t foc_pwm_period(void)
+{
+    uint16_t per1 = tim_period(&htim1);
+    uint16_t per8 = tim_period(&htim8);
+
+    if(per1 == 0U) per1 = 1U;
+    if(per8 == 0U) per8 = 1U;
+
+    return (per1 < per8) ? per1 : per8;
+}
+
+static inline uint16_t clamp_u16(uint32_t value, uint16_t hi)
+{
+    return (value > hi) ? hi : (uint16_t)value;
+}
+
+static inline float clamp_f32(float value, float lo, float hi)
+{
+    if(value < lo) return lo;
+    if(value > hi) return hi;
+    return value;
+}
+
+static inline float foc_bus_voltage(void)
+{
+    return (vol > 1.0f) ? vol : 24.0f;
+}
+
+static inline float angle_q10_to_rad(uint16_t angle)
+{
+    return ((float)(angle & 0x03FFU)) * (2.0f * M_PI / 1024.0f);
+}
+
+static inline void hb_off(TIM_HandleTypeDef *htim, uint32_t ch)
+{
+    HAL_TIM_PWM_Stop(htim, ch);
+    HAL_TIMEx_PWMN_Stop(htim, ch);
+}
+
+static inline void hb_low(TIM_HandleTypeDef *htim, uint32_t ch)
