            break;

        case 2U:
            if(mfoc->Ta <= threshold) { HN1_off(); HN2_off(); }
            else { HN1_low(); HN2_set(duty_a); }

            if(mfoc->Tb <= threshold) { HN3_off(); HN4_off(); }
            else { HN3_set(duty_b); HN4_low(); }
            break;

        case 3U:
            if(mfoc->Ta <= threshold) { HN1_off(); HN2_off(); }
            else { HN1_low(); HN2_set(duty_a); }

            if(mfoc->Tb <= threshold) { HN3_off(); HN4_off(); }
            else { HN3_low(); HN4_set(duty_b); }
            break;

        case 4U:
            if(mfoc->Ta <= threshold) { HN1_off(); HN2_off(); }
            else { HN1_set(duty_a); HN2_low(); }

            if(mfoc->Tb <= threshold) { HN3_off(); HN4_off(); }
            else { HN3_low(); HN4_set(duty_b); }
            break;

        default:
            FOC_AllOff();
            break;
    }
}

void set_uduq(foc_TypeDef *mfoc, float ud, float uq)
{
    ud = clamp_f32(ud, -mfoc->outmax, mfoc->outmax);
    uq = clamp_f32(uq, -mfoc->outmax, mfoc->outmax);

    mfoc->Ud = ud;
    mfoc->Uq = uq;
}

void foc_open(foc_TypeDef *mfoc, uint16_t angle)
{
    setfoc_angle(mfoc, angle);
    repark_transfer(mfoc);
    svpwmctr(mfoc);
    set_duty_by_sector(mfoc);
}

void park_transform(foc_TypeDef *mfoc)
{
    mfoc->Iq = -mfoc->Ialpha * mfoc->sintheta + mfoc->Ibeta * mfoc->costheta;
    mfoc->Id =  mfoc->Ialpha * mfoc->costheta + mfoc->Ibeta * mfoc->sintheta;
}

void get_AB_current(foc_TypeDef *mfoc)
{
    current[0] = ADCtoI * HAL_ADCEx_InjectedGetValue(&hadc1, ADC_INJECTED_RANK_1) - offet_I[0];
    current[1] = ADCtoI * HAL_ADCEx_InjectedGetValue(&hadc1, ADC_INJECTED_RANK_2) - offet_I[1];

    switch(mfoc->sector)
    {
        case 1U:
            mfoc->Ialpha = current[0];
            mfoc->Ibeta  = current[1];
            break;

        case 2U:
            mfoc->Ialpha = -current[0];
            mfoc->Ibeta  = current[1];
            break;

        case 3U:
            mfoc->Ialpha = -current[0];
            mfoc->Ibeta  = -current[1];
            break;

        case 4U:
            mfoc->Ialpha = current[0];
            mfoc->Ibeta  = -current[1];
            break;

        default:
            mfoc->Ialpha = 0.0f;
            mfoc->Ibeta = 0.0f;
            break;
    }
}

float PID_factor = 1.0f;

void adjust_I(void)
{
    current[0] = ADCtoI * HAL_ADCEx_InjectedGetValue(&hadc1, ADC_INJECTED_RANK_1);
    current[1] = ADCtoI * HAL_ADCEx_InjectedGetValue(&hadc1, ADC_INJECTED_RANK_2);
}

void can_foc_init(void)
{
    m1_foc.Ts = foc_pwm_period();
    m1_foc.Udc = foc_bus_voltage();
    m1_foc.outmax = 0.5f * m1_foc.Udc;
    m1_foc.deadband = 0.0f;

    if(PID_factor > 2.0f || PID_factor < 0.5f)
        PID_factor = 1.0f;

    m1_foc.kp = (3.0f - vol * 0.06f) * PID_factor;
    m1_foc.ki = (0.06f - vol * 0.001f) * PID_factor;
    m1_foc.kd = 0.0f;

    if(m1_foc.kp < 0.2f) m1_foc.kp = 0.2f;
    if(m1_foc.ki < 0.001f) m1_foc.ki = 0.001f;

    m1_foc.tar_Id = 0.0f;
    m1_foc.tar_Iq = 0.5f;
    m1_foc.id_err = 0.0f;
    m1_foc.iq_err = 0.0f;
    m1_foc.last_Id_err = 0.0f;
    m1_foc.last_Iq_err = 0.0f;
    m1_foc.id_inter = 0.0f;
    m1_foc.iq_inter = 0.0f;
    m1_foc.Ialpha = 0.0f;
    m1_foc.Ibeta = 0.0f;
    m1_foc.Id = 0.0f;
    m1_foc.Iq = 0.0f;
    m1_foc.Ud = 0.0f;
    m1_foc.Uq = 0.0f;
    m1_foc.angle = 0;
    m1_foc.angle_sector = 0U;
    m1_foc.scope = 82;
    m1_foc.sector = 1U;
    m1_foc.Ls = 0.0041f;
    m1_foc.FLux = 0.002f;
}

void b_foc_init(void)
{
    add_angle = 0U;
    PID_factor = (*(__IO uint32_t *)(FLASH_USER_START_ADDR + 0x800)) * 0.01f;

    can_foc_init();
    FOC_Init();

    set_uduq(&m1_foc, 0.0f, 0.0f);
    foc_open(&m1_foc, 0U);

    for(uint16_t i = 0U; i < 250U; i++)
    {
        add_angle += (uint32_t)REIN_MT6816_GetAngleData();
        HAL_Delay(1);
    }

    encoder_last_count = mt6816_count = init_angle = (uint16_t)(add_angle / 250U);
}

void set_foc_Iqcurrent(foc_TypeDef *mfoc, float current_set)
{
    if(current_set > System_MAX_I) current_set = System_MAX_I;
    else if(current_set < -System_MAX_I) current_set = -System_MAX_I;

    mfoc->tar_Iq = current_set;
}

#define OMAX_UQ 10.0f
#define OMAX_UD 6.0f

void foc_current_pid(foc_TypeDef *mfoc)
{
    mfoc->id_err = mfoc->tar_Id - mfoc->Id;
    mfoc->iq_err = mfoc->tar_Iq - mfoc->Iq;

    mfoc->id_inter += mfoc->ki * mfoc->id_err;
    mfoc->iq_inter += mfoc->ki * mfoc->iq_err;

    mfoc->id_inter = clamp_f32(mfoc->id_inter, -(float)limit_vol, (float)limit_vol);
    mfoc->iq_inter = clamp_f32(mfoc->iq_inter, -(float)limit_vol, (float)limit_vol);

    mfoc->Ud = mfoc->kp * mfoc->id_err + mfoc->id_inter + mfoc->kd * (mfoc->id_err - mfoc->last_Id_err);
    mfoc->Uq = mfoc->kp * mfoc->iq_err + mfoc->iq_inter + mfoc->kd * (mfoc->iq_err - mfoc->last_Iq_err);

    mfoc->Ud = clamp_f32(mfoc->Ud, -OMAX_UD, OMAX_UD);
    mfoc->Uq = clamp_f32(mfoc->Uq, -OMAX_UQ, OMAX_UQ);

    mfoc->last_Id_err = mfoc->id_err;
    mfoc->last_Iq_err = mfoc->iq_err;
}

void current_ctr(foc_TypeDef *mfoc, uint16_t angle)
{
    setfoc_angle(mfoc, angle);
    park_transform(mfoc);
    foc_current_pid(mfoc);
    repark_transfer(mfoc);
    svpwmctr(mfoc);
    set_duty_by_sector(mfoc);
}

