void set_duty_by_sector(foc_TypeDef *mfoc)
{
    uint16_t ts = foc_pwm_period();
    uint16_t ta_inv = (mfoc->Ta >= ts) ? 0U : (uint16_t)(ts - mfoc->Ta);
    uint16_t tb_inv = (mfoc->Tb >= ts) ? 0U : (uint16_t)(ts - mfoc->Tb);

    switch(mfoc->sector)
    {
        case 1U:
            HN4_set(ts);
            HN3_set(ta_inv);
            HN2_set(ts);
            HN1_set(tb_inv);
            break;

        case 2U:
            HN3_set(ts);
            HN4_set(ta_inv);
            HN2_set(ts);
            HN1_set(tb_inv);
            break;

        case 3U:
            HN3_set(ts);
            HN4_set(ta_inv);
            HN1_set(ts);
            HN2_set(tb_inv);
            break;

        case 4U:
            HN4_set(ts);
            HN3_set(ta_inv);
            HN1_set(ts);
            HN2_set(tb_inv);
            break;

        default:
            FOC_AllOff();
            break;
    }
