    mfoc->Ud = clamp_f32(mfoc->Ud, -OMAX_UD, OMAX_UD);
    mfoc->Uq = clamp_f32(mfoc->Uq, -OMAX_UQ, OMAX_UQ);

    mfoc->last_Id_err = mfoc->id_err;
    mfoc->last_Iq_err = mfoc->iq_err;
}

