            Encoder_Update();
            get_AB_current(&m1_foc);
            Sector_tracker();

            foc_angle = (uint16_t)((m1_foc.angle + 256 * (m1_foc.angle_sector % 4) + m1_foc.lead_angle) & 0x03FF);
