#include "FOC.h"
#include "tim.h"
#include "math.h"
#include "adc.h"
#include "adc_task.h"
#include "myflash.h"
#include "mt6816.h"
#include "pid.h"

#ifndef M_PI
#define M_PI 3.14159265358979323846f
#endif

foc_TypeDef m1_foc;

extern uint16_t mt6816_count;
extern float current[2];
extern float vol;
extern uint8_t limit_vol;
extern uint32_t add_angle;

uint16_t bias = 0;
int16_t Scope[200];
uint16_t angledata[200] = {0};

static inline uint16_t tim_period(TIM_HandleTypeDef *htim)
{
    return (uint16_t)(__HAL_TIM_GET_AUTORELOAD(htim) + 1U);
}

static inline uint16_t foc_pwm_ts(void)
{
    uint16_t arr1 = (uint16_t)__HAL_TIM_GET_AUTORELOAD(&htim1);
    uint16_t arr8 = (uint16_t)__HAL_TIM_GET_AUTORELOAD(&htim8);
    return (arr1 < arr8) ? arr1 : arr8;
}

static inline uint16_t foc_pwm_period(void)
{
    uint16_t per1 = tim_period(&htim1);
    uint16_t per8 = tim_period(&htim8);

    if(per1 == 0U) per1 = 1U;
    if(per8 == 0U) per8 = 1U;

    return (per1 < per8) ? per1 : per8;
}

static inline uint16_t clamp_u16(uint32_t value, uint16_t hi)
{
    return (value > hi) ? hi : (uint16_t)value;
}

static inline float clamp_f32(float value, float lo, float hi)
{
    if(value < lo) return lo;
    if(value > hi) return hi;
    return value;
}

static inline float foc_bus_voltage(void)
{
    return (vol > 1.0f) ? vol : 24.0f;
}

static inline float angle_q10_to_rad(uint16_t angle)
{
    return ((float)(angle & 0x03FFU)) * (2.0f * M_PI / 1024.0f);
}

static inline void hb_off(TIM_HandleTypeDef *htim, uint32_t ch)
{
    HAL_TIM_PWM_Stop(htim, ch);
    HAL_TIMEx_PWMN_Stop(htim, ch);
}

static inline void hb_low(TIM_HandleTypeDef *htim, uint32_t ch)
{
    HAL_TIM_PWM_Start(htim, ch);
    HAL_TIMEx_PWMN_Start(htim, ch);
    __HAL_TIM_SET_COMPARE(htim, ch, 0U);
}

static inline void hb_pwm(TIM_HandleTypeDef *htim, uint32_t ch, uint16_t duty)
{
    HAL_TIM_PWM_Start(htim, ch);
    HAL_TIMEx_PWMN_Start(htim, ch);
    __HAL_TIM_SET_COMPARE(htim, ch, duty);
}

static inline void HN1_off(void) { hb_off(&htim1, TIM_CHANNEL_1); }
static inline void HN2_off(void) { hb_off(&htim1, TIM_CHANNEL_2); }
static inline void HN3_off(void) { hb_off(&htim1, TIM_CHANNEL_3); }
static inline void HN4_off(void) { hb_off(&htim8, TIM_CHANNEL_1); }

static inline void HN1_low(void) { hb_low(&htim1, TIM_CHANNEL_1); }
static inline void HN2_low(void) { hb_low(&htim1, TIM_CHANNEL_2); }
static inline void HN3_low(void) { hb_low(&htim1, TIM_CHANNEL_3); }
static inline void HN4_low(void) { hb_low(&htim8, TIM_CHANNEL_1); }

static inline void HN1_set(uint16_t duty) { hb_pwm(&htim1, TIM_CHANNEL_1, duty); }
static inline void HN2_set(uint16_t duty) { hb_pwm(&htim1, TIM_CHANNEL_2, duty); }
static inline void HN3_set(uint16_t duty) { hb_pwm(&htim1, TIM_CHANNEL_3, duty); }
static inline void HN4_set(uint16_t duty) { hb_pwm(&htim8, TIM_CHANNEL_1, duty); }

void FOC_AllOff(void)
{
    HN1_off();
    HN2_off();
    HN3_off();
    HN4_off();
}

void get_scope(void)
{
    Flash_Read_Angle(angledata);
    Flash_Read_Angle(angledata);
    bias = 0;

    for(uint8_t i = 0; i < 200; i++)
    {
        if(i != 199)
            Scope[i] = DIR * (int16_t)(angledata[i + 1] - angledata[i]);
        else
            Scope[i] = DIR * (int16_t)(angledata[0] - angledata[i]);

        if(abs(Scope[i]) > 2000)
        {
            Scope[i] = 16384 + Scope[i];
            bias = i;
        }
    }

    Scope[0] = (int16_t)((Scope[0] + Scope[199] + Scope[198] + Scope[197]) * 0.25f);
    Scope[199] = Scope[0];
}

void FOC_Init(void)
{
    if(flash_read_dir(DIR_AD) == 11U)
        DIR = 1;
    else
        DIR = -1;

    set_uduq(&m1_foc, 0.0f, 0.5f);
    foc_open(&m1_foc, 0U);
    HAL_Delay(100);

    m1_foc.lead_angle = 256;
    get_scope();
}

void Sector_tracker(void)
{
    int temp = (DIR * ((int)mt6816_count / 82) + bias + 200) % 200;

    for(int i = temp - 1; i <= temp + 1; i++)
    {
        int idx = (i + 200) % 200;
        int next = (idx + 1) % 200;

        if(DIR == 1)
        {
            if(angledata[next] > angledata[idx])
            {
                if(mt6816_count >= angledata[idx] && mt6816_count <= angledata[next])
                {
                    m1_foc.angle_sector = (uint8_t)idx;
                    break;
                }
            }
            else if(angledata[next] < angledata[idx])
            {
                if(mt6816_count >= angledata[idx] && mt6816_count <= (angledata[next] + 16384))
                {
                    m1_foc.angle_sector = (uint8_t)idx;
                    break;
                }
            }
        }
        else
        {
            if(angledata[next] < angledata[idx])
            {
                if(mt6816_count <= angledata[idx] && mt6816_count >= angledata[next])
                {
                    m1_foc.angle_sector = (uint8_t)idx;
                    break;
                }
            }
            else if(angledata[next] > angledata[idx])
            {
                if(mt6816_count <= angledata[idx] && (mt6816_count + 16384) >= angledata[next])
                {
                    m1_foc.angle_sector = (uint8_t)idx;
                    break;
                }
            }
        }
    }

    m1_foc.scope = Scope[m1_foc.angle_sector];
    if(m1_foc.scope == 0)
        m1_foc.scope = 82;

    if(DIR * angledata[(m1_foc.angle_sector + 1) % 200] > DIR * angledata[m1_foc.angle_sector])
    {
        m1_foc.angle = (int16_t)(DIR * ((int32_t)mt6816_count - angledata[m1_foc.angle_sector]) * 256 / m1_foc.scope);
    }
    else
    {
        if(DIR == 1)
        {
            if(mt6816_count > 16200)
                m1_foc.angle = (int16_t)(((int32_t)mt6816_count - angledata[m1_foc.angle_sector]) * 256 / m1_foc.scope);
            else
                m1_foc.angle = (int16_t)((16384 - angledata[m1_foc.angle_sector] + (int32_t)mt6816_count) * 256 / m1_foc.scope);
        }
        else
        {
            if(mt6816_count > 16200)
                m1_foc.angle = (int16_t)((16384 + angledata[m1_foc.angle_sector] - (int32_t)mt6816_count) * 256 / m1_foc.scope);
            else
                m1_foc.angle = (int16_t)((-(int32_t)mt6816_count + angledata[m1_foc.angle_sector]) * 256 / m1_foc.scope);
        }
    }
}

void setfoc_angle(foc_TypeDef *mfoc, uint16_t angle)
{
    float rad = angle_q10_to_rad(angle);
    mfoc->sintheta = sinf(rad);
    mfoc->costheta = cosf(rad);
}

void repark_transfer(foc_TypeDef *mfoc)
{
    mfoc->Ualpha = mfoc->costheta * mfoc->Ud - mfoc->sintheta * mfoc->Uq;
    mfoc->Ubeta  = mfoc->sintheta * mfoc->Ud + mfoc->costheta * mfoc->Uq;
}

void svpwmctr(foc_TypeDef *mfoc)
{
    float ualpha = fabsf(mfoc->Ualpha);
    float ubeta = fabsf(mfoc->Ubeta);

    if(mfoc->Ualpha >= 0.0f && mfoc->Ubeta >= 0.0f)
        mfoc->sector = 1U;
    else if(mfoc->Ualpha < 0.0f && mfoc->Ubeta >= 0.0f)
        mfoc->sector = 2U;
    else if(mfoc->Ualpha < 0.0f && mfoc->Ubeta < 0.0f)
        mfoc->sector = 3U;
    else
        mfoc->sector = 4U;

    mfoc->Udc = foc_bus_voltage();
    mfoc->Ts = foc_pwm_ts();
    mfoc->Ta = clamp_u16((uint32_t)(ualpha / mfoc->Udc * mfoc->Ts), mfoc->Ts);
    mfoc->Tb = clamp_u16((uint32_t)(ubeta / mfoc->Udc * mfoc->Ts), mfoc->Ts);
}

void set_duty_by_sector(foc_TypeDef *mfoc)
{
    uint16_t ts = foc_pwm_period();
    uint16_t ta_inv = (mfoc->Ta >= ts) ? 0U : (uint16_t)(ts - mfoc->Ta);
    uint16_t tb_inv = (mfoc->Tb >= ts) ? 0U : (uint16_t)(ts - mfoc->Tb);

    switch(mfoc->sector)
    {
        case 1U:
            HN4_set(ts);
            HN3_set(ta_inv);
            HN2_set(ts);
            HN1_set(tb_inv);
            break;

        case 2U:
            HN3_set(ts);
            HN4_set(ta_inv);
            HN2_set(ts);
            HN1_set(tb_inv);
            break;

        case 3U:
            HN3_set(ts);
            HN4_set(ta_inv);
            HN1_set(ts);
            HN2_set(tb_inv);
            break;

        case 4U:
            HN4_set(ts);
            HN3_set(ta_inv);
            HN1_set(ts);
            HN2_set(tb_inv);
            break;

        default:
            FOC_AllOff();
            break;
    }
}

void set_uduq(foc_TypeDef *mfoc, float ud, float uq)
{
    if(ud > mfoc->outmax) return;
    else if(ud < -mfoc->outmax) return;

    if(uq > mfoc->outmax) return;
    else if(uq < -mfoc->outmax) return;

    mfoc->Ud = ud;
    mfoc->Uq = uq;
}

void foc_open(foc_TypeDef *mfoc, uint16_t angle)
{
    setfoc_angle(mfoc, angle);
    repark_transfer(mfoc);
    svpwmctr(mfoc);
    set_duty_by_sector(mfoc);
}

void park_transform(foc_TypeDef *mfoc)
{
    mfoc->Iq = -mfoc->Ialpha * mfoc->sintheta + mfoc->Ibeta * mfoc->costheta;
    mfoc->Id =  mfoc->Ialpha * mfoc->costheta + mfoc->Ibeta * mfoc->sintheta;
}

void get_AB_current(foc_TypeDef *mfoc)
{
    mfoc->Ialpha = current[0] = ADCtoI * HAL_ADCEx_InjectedGetValue(&hadc1, ADC_INJECTED_RANK_2) - offet_I[0];
    mfoc->Ibeta  = current[1] = ADCtoI * HAL_ADCEx_InjectedGetValue(&hadc1, ADC_INJECTED_RANK_1) - offet_I[1];
}

float PID_factor = 1.0f;

void adjust_I(void)
{
    current[0] = ADCtoI * HAL_ADCEx_InjectedGetValue(&hadc1, ADC_INJECTED_RANK_2);
    current[1] = ADCtoI * HAL_ADCEx_InjectedGetValue(&hadc1, ADC_INJECTED_RANK_1);
}

void can_foc_init(void)
{
    m1_foc.Ts = foc_pwm_ts();
    m1_foc.Udc = 24.0f;
    m1_foc.outmax = 10.0f;
    m1_foc.deadband = 0.0f;

    if(PID_factor > 10.0f || PID_factor < 0.1f)
        PID_factor = 1.0f;

    m1_foc.kp = 1.2f * PID_factor;
    m1_foc.ki = 0.02f * PID_factor;
    if(m1_foc.ki > 0.1f) m1_foc.ki = 0.1f;
    m1_foc.kd = 0.0f;

    m1_foc.tar_Id = 0.0f;
    m1_foc.tar_Iq = -0.0f;
    m1_foc.id_err = 0.0f;
    m1_foc.iq_err = 0.0f;
    m1_foc.last_Id_err = 0.0f;
    m1_foc.last_Iq_err = 0.0f;
    m1_foc.id_inter = 0.0f;
    m1_foc.iq_inter = 0.0f;
    m1_foc.Ialpha = 0.0f;
    m1_foc.Ibeta = 0.0f;
    m1_foc.Id = 0.0f;
    m1_foc.Iq = 0.0f;
    m1_foc.Ud = 0.0f;
    m1_foc.Uq = 0.0f;
    m1_foc.angle = 0;
    m1_foc.angle_sector = 0U;
    m1_foc.scope = 82;
    m1_foc.sector = 1U;
    m1_foc.Ls = 0.00002f;
    m1_foc.FLux = 0.0035f;
}

void b_foc_init(void)
{
    add_angle = 0U;
    PID_factor = (*(__IO uint32_t *)(FLASH_USER_START_ADDR + 0x800)) * 0.01f;

    can_foc_init();
    FOC_Init();

    set_uduq(&m1_foc, 0.0f, 0.0f);
    foc_open(&m1_foc, 0U);

    for(uint16_t i = 0U; i < 250U; i++)
    {
        add_angle += (uint32_t)REIN_MT6816_GetAngleData();
        HAL_Delay(1);
    }

    encoder_last_count = mt6816_count = init_angle = (uint16_t)(add_angle / 250U);
}

void set_foc_Iqcurrent(foc_TypeDef *mfoc, float current_set)
{
    if(current_set > System_MAX_I) current_set = System_MAX_I;
    else if(current_set < -System_MAX_I) current_set = -System_MAX_I;

    mfoc->tar_Iq = current_set;
}

#define Omax 8.0f

void foc_current_pid(foc_TypeDef *mfoc)
{
    mfoc->id_err = mfoc->tar_Id - mfoc->Id;
    mfoc->iq_err = mfoc->tar_Iq - mfoc->Iq;

    mfoc->id_inter += mfoc->ki * mfoc->id_err;
    mfoc->iq_inter += mfoc->ki * mfoc->iq_err;

    if(mfoc->id_inter > 8.0f) mfoc->id_inter = 8.0f;
    if(mfoc->id_inter < -8.0f) mfoc->id_inter = -8.0f;

    if(mfoc->iq_inter > 10.0f) mfoc->iq_inter = 10.0f;
    if(mfoc->iq_inter < -10.0f) mfoc->iq_inter = -10.0f;

    mfoc->Ud = mfoc->kp * mfoc->id_err + mfoc->id_inter + mfoc->kd * (mfoc->id_err - mfoc->last_Id_err);
    mfoc->Uq = mfoc->kp * mfoc->iq_err + mfoc->iq_inter + mfoc->kd * (mfoc->iq_err - mfoc->last_Iq_err);

    if(mfoc->Ud > Omax) mfoc->Ud = Omax;
    if(mfoc->Ud < -Omax) mfoc->Ud = -Omax;

    if(mfoc->Uq > Omax) mfoc->Uq = Omax;
    if(mfoc->Uq < -Omax) mfoc->Uq = -Omax;

    mfoc->last_Id_err = mfoc->id_err;
    mfoc->last_Iq_err = mfoc->iq_err;
}

void current_ctr(foc_TypeDef *mfoc, uint16_t angle)
{
    setfoc_angle(mfoc, angle);
    park_transform(mfoc);
    foc_current_pid(mfoc);
    repark_transfer(mfoc);
    svpwmctr(mfoc);
