// ====================== 按扇区下发到你的四路半桥 ======================
void set_duty_by_sector(foc_TypeDef *mfoc)
{
    uint16_t per1 = tim_period(&htim1);
    uint16_t per8 = tim_period(&htim8);

    // A相占空基于TIM1
    uint16_t dutyA = clamp_u16(mfoc->Ta, per1);

    // B相占空最好要求TIM1/TIM8 ARR一致
    // 若不一致，这里按TIM8限制
    uint16_t dutyB = clamp_u16(mfoc->Tb, per8);

    // 小占空直接关断
    if ((mfoc->Ta <= (uint16_t)(mfoc->deadband * mfoc->Ts)) &&
        (mfoc->Tb <= (uint16_t)(mfoc->deadband * mfoc->Ts)))
    {
        FOC_AllOff();
        return;
    }

    switch (mfoc->sector)
    {
        case 1: // A+, B+
            if (mfoc->Ta <= (uint16_t)(mfoc->deadband * mfoc->Ts)) {
                HN1_off(); HN2_off();
            } else {
                HN1_set(dutyA);
                HN2_low();
            }

            if (mfoc->Tb <= (uint16_t)(mfoc->deadband * mfoc->Ts)) {
                HN3_off(); HN4_off();
            } else {
                HN3_set(dutyB);
                HN4_low();
            }
            break;

        case 2: // A-, B+
            if (mfoc->Ta <= (uint16_t)(mfoc->deadband * mfoc->Ts)) {
                HN1_off(); HN2_off();
            } else {
                HN1_low();
                HN2_set(dutyA);
            }

            if (mfoc->Tb <= (uint16_t)(mfoc->deadband * mfoc->Ts)) {
                HN3_off(); HN4_off();
            } else {
                HN3_set(dutyB);
                HN4_low();
            }
            break;

        case 3: // A-, B-
            if (mfoc->Ta <= (uint16_t)(mfoc->deadband * mfoc->Ts)) {
                HN1_off(); HN2_off();
            } else {
                HN1_low();
                HN2_set(dutyA);
            }

            if (mfoc->Tb <= (uint16_t)(mfoc->deadband * mfoc->Ts)) {
                HN3_off(); HN4_off();
            } else {
                HN3_low();
                HN4_set(dutyB);
            }
            break;

        case 4: // A+, B-
            if (mfoc->Ta <= (uint16_t)(mfoc->deadband * mfoc->Ts)) {
                HN1_off(); HN2_off();
            } else {
                HN1_set(dutyA);
                HN2_low();
            }

            if (mfoc->Tb <= (uint16_t)(mfoc->deadband * mfoc->Ts)) {
                HN3_off(); HN4_off();
            } else {
                HN3_low();
                HN4_set(dutyB);
            }
            break;

        default:
            FOC_AllOff();
            break;
    }
